 {"id":"jeffreysprompts.com-dio8","title":"Implement automatic token refresh in CLI","description":"## Task
Add automatic token refresh to the CLI when access tokens expire.

## Why
Users shouldn't have to manually re-login every 24 hours. The CLI should:
1. Detect when access token is expired (or about to expire)
2. Automatically use refresh token to get new access token
3. Only prompt for re-login when refresh token also expires (30 days)

## Implementation

### Update `packages/cli/src/lib/credentials.ts`

```typescript
const PREMIUM_URL = process.env.JFP_PREMIUM_URL ?? "https://premium.jeffreysprompts.com";

/**
 * Get a valid access token, refreshing if necessary
 * Returns null if not logged in or refresh fails
 */
export async function getValidAccessToken(): Promise<string | null> {
  // Check environment variable first (CI/CD)
  const envToken = process.env.JFP_TOKEN;
  if (envToken) {
    return envToken;
  }

  const creds = await loadCredentials();
  if (!creds) {
    return null;
  }

  // If not expired, return current token
  if (!isExpired(creds)) {
    return creds.access_token;
  }

  // Try to refresh
  if (creds.refresh_token) {
    const refreshed = await refreshAccessToken(creds.refresh_token);
    if (refreshed) {
      // Save new credentials
      await saveCredentials(refreshed);
      return refreshed.access_token;
    }
  }

  // Refresh failed or no refresh token
  return null;
}

/**
 * Attempt to refresh the access token
 */
async function refreshAccessToken(refreshToken: string): Promise<Credentials | null> {
  try {
    const response = await fetch(`${PREMIUM_URL}/api/cli/token/refresh`, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        refresh_token: refreshToken,
        client_id: "jfp-cli",
      }),
    });

    if (!response.ok) {
      // Refresh failed - token likely expired or revoked
      return null;
    }

    const data = await response.json();

    return {
      access_token: data.access_token,
      refresh_token: data.refresh_token,
      expires_at: data.expires_at,
      email: data.email,
      tier: data.tier,
      user_id: data.user_id,
    };
  } catch {
    // Network error - return null to fail gracefully
    return null;
  }
}

/**
 * Check if credentials need refresh (expired or expiring soon)
 */
export function needsRefresh(creds: Credentials): boolean {
  if (!creds.expires_at) return false;

  const expiresAt = new Date(creds.expires_at);
  const now = new Date();

  // Refresh if expiring within 5 minutes
  const bufferMs = 5 * 60 * 1000;
  return now.getTime() > expiresAt.getTime() - bufferMs;
}
```

### Update API Client

The API client should use `getValidAccessToken()` instead of directly reading credentials:

```typescript
// packages/cli/src/lib/api-client.ts
import { getValidAccessToken, isLoggedIn } from "./credentials";

export async function authenticatedFetch(
  url: string,
  options: RequestInit = {}
): Promise<Response> {
  const token = await getValidAccessToken();

  const headers = new Headers(options.headers);
  if (token) {
    headers.set("Authorization", `Bearer ${token}`);
  }

  return fetch(url, {
    ...options,
    headers,
  });
}
```

## User Experience
- If token refreshes successfully: User never notices, command works
- If refresh fails: User sees "Session expired. Please run 'jfp login' to sign in again."
- Never show technical error details to user

## Logging
Add debug logging for troubleshooting:
```typescript
if (process.env.JFP_DEBUG) {
  console.error("[jfp] Access token expired, attempting refresh...");
  console.error("[jfp] Refresh successful, new token expires:", creds.expires_at);
}
```

